#if DEBUG
import Foundation
import SwiftData

/// スクリーンショット用のサンプルデータ（DEBUG ビルドのみ）。
/// データが空のときに一度だけ、間取り図つきのデモ間取り＋マーカーを投入する。
/// リリースビルドには一切含まれない（#if DEBUG で囲っている）。
enum SampleData {
    static func seedIfNeeded(_ context: ModelContext) {
        let existing = (try? context.fetchCount(FetchDescriptor<FloorPlan>())) ?? 0
        guard existing == 0 else { return }

        let plan = FloorPlan(name: "1階", imageData: Data(base64Encoded: floorPlanBase64))
        context.insert(plan)

        func add(_ x: Double, _ y: Double, _ kind: MarkerKind, _ note: String,
                 pest: PestType = .none, days: Int? = nil, repeatInterval: RepeatInterval = .none) {
            let marker = PestMarker(x: x, y: y, kind: kind, note: note)
            marker.pestType = pest
            marker.repeatInterval = repeatInterval
            if let days {
                marker.nextActionDate = Calendar.current.date(byAdding: .day, value: days, to: Date())
            }
            marker.plan = plan
            context.insert(marker)
            plan.markers.append(marker)
        }

        add(0.28, 0.62, .blackCap, "シンク下", pest: .cockroach, days: 20, repeatInterval: .every3Months)
        add(0.72, 0.30, .blackCap, "冷蔵庫の裏", pest: .cockroach, days: -3, repeatInterval: .every3Months) // 期限切れ
        add(0.50, 0.86, .spray, "玄関", pest: .ant)
        add(0.25, 0.25, .fumigation, "寝室", pest: .mite, days: 80, repeatInterval: .every6Months)
        add(0.80, 0.70, .other, "窓際", pest: .mosquito)

        try? context.save()
    }

    private static let floorPlanBase64 = ""
}
#endif
